mapper.select:
SELECT id, code, name, type, location, address, contact, phone, create_time, default_area_code FROM merchant
type IN ('机构', '保司') AND is_delete = 0
AND id = #{id}
AND (code LIKE CONCAT('%', #{blurParam}, '%') OR name LIKE CONCAT('%', #{blurParam}, '%'))
AND location = #{location}
AND id IN ( SELECT merchant_id FROM merchant_area WHERE area_code = #{businessArea} AND is_delete = 0 )

SELECT m.id, m.code, m.name, m.type, m.location, m.address, m.bank, m.bank_card_num, m.channel, m.default_area_code, manager.name AS store_manager, m.create_time FROM merchant m LEFT JOIN ( SELECT u.merchant_id AS merchant_id, ANY_VALUE(u.name) AS name FROM user u INNER JOIN user_role ur ON u.id = ur.user_id AND ur.is_delete = 0 INNER JOIN role r ON ur.role_id = r.id AND r.is_delete = 0 WHERE u.is_delete = 0 AND r.name = '联系人' GROUP BY u.merchant_id ) manager ON m.id = manager.merchant_id
m.type IN ('车商店铺', '汽修厂', '代理人') AND m.is_delete = 0
AND m.id = #{id}
AND (m.code LIKE CONCAT('%', #{blurParam}, '%') OR m.name LIKE CONCAT('%', #{blurParam}, '%'))
AND m.location = #{location}
AND m.channel = #{channel}
AND m.id IN ( SELECT merchant_id FROM merchant_area WHERE area_code = #{businessArea} AND is_delete = 0 )
